script:
frappe.ui.form.on("Student Admit Card", {
    student(frm) {

        if (!frm.doc.student) return;

        frappe.db.get_doc("Custom Student", frm.doc.student)
            .then(doc => {

                frm.set_value("student_name", doc.student_name);
                frm.set_value("register_number", doc.register_number);
                frm.set_value("roll_number", doc.roll_number);
                frm.set_value("student_class", doc.program);
                frm.set_value("section", doc.section);
                frm.set_value("photo", doc.student_photo);

            });

    }
});
